import java.util.*;
public class Leaky {
    private List<String> items = new ArrayList<>();
    void add(String s) { items.add(s); }
    List<String> getItems() { return items; }  // returns internal list
    public static void main(String[] args) {
        Leaky l = new Leaky();
        l.add("a");
        List<String> ref = l.getItems();
        ref.add("injected");  // modifies internal state!
        System.out.println(l.getItems().size());
    }
}
